import{_ as a,o as t,c as s,i as o}from"./chunks/framework.DP1yFSuu.js";const c=JSON.parse('{"title":"Help, Feedback & Support FAQ","description":"Common questions about support channels, migration help, issues, discussions, and expected response times.","frontmatter":{"title":"Help, Feedback & Support FAQ","description":"Common questions about support channels, migration help, issues, discussions, and expected response times."},"headers":[],"relativePath":"faqs/help-feedback-and-support.md","filePath":"faqs/help-feedback-and-support.md"}'),i={name:"faqs/help-feedback-and-support.md"};function r(n,e,l,u,d,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="help-feedback-support-faq" tabindex="-1">Help, Feedback &amp; Support FAQ <a class="header-anchor" href="#help-feedback-support-faq" aria-label="Permalink to &quot;Help, Feedback &amp; Support FAQ&quot;">​</a></h1><p>These questions cover where to go when you are blocked, want to report a problem, or need to give feedback on Cobalt.</p><h2 id="where-do-i-ask-a-question" tabindex="-1">Where do I ask a question? <a class="header-anchor" href="#where-do-i-ask-a-question" aria-label="Permalink to &quot;Where do I ask a question?&quot;">​</a></h2><p>Start with <a href="https://github.com/vizualization-lab/cobalt-design-system/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a> for open-ended questions, early idea checks, and “which path is right?” conversations.</p><p>If you already know you need structured follow-up, use the issue templates instead.</p><p>The <a href="/cobalt-design-system/resources/contact.html">Contact</a> page is the central index for these support channels.</p><h2 id="when-should-i-open-an-issue-versus-a-discussion" tabindex="-1">When should I open an Issue versus a Discussion? <a class="header-anchor" href="#when-should-i-open-an-issue-versus-a-discussion" aria-label="Permalink to &quot;When should I open an Issue versus a Discussion?&quot;">​</a></h2><p>Use <strong>Issues</strong> when you need an actionable tracked item:</p><ul><li>bug reports</li><li>feature requests</li><li>migration help</li><li>structured support requests</li></ul><p>Use <strong>Discussions</strong> when you need conversation first:</p><ul><li>early design feedback</li><li>proposal shaping</li><li>architecture questions</li><li>onboarding questions that may not require code changes</li></ul><h2 id="how-do-i-request-migration-help" tabindex="-1">How do I request migration help? <a class="header-anchor" href="#how-do-i-request-migration-help" aria-label="Permalink to &quot;How do I request migration help?&quot;">​</a></h2><p>Open a GitHub issue using the migration-help template and include:</p><ul><li>current framework and UI stack</li><li>target Cobalt packages or docs</li><li>the step you are blocked on</li><li>what you already tried</li><li>any timeline or rollout constraints</li></ul><p>The contributor-facing details are summarized in <a href="/cobalt-design-system/contributing/how-to-contribute.html">How to Contribute</a>.</p><h2 id="how-do-i-report-a-bug-or-request-a-feature" tabindex="-1">How do I report a bug or request a feature? <a class="header-anchor" href="#how-do-i-report-a-bug-or-request-a-feature" aria-label="Permalink to &quot;How do I report a bug or request a feature?&quot;">​</a></h2><p>Use the GitHub issue templates:</p><ul><li><strong>Bug Report</strong> for regressions or incorrect behavior</li><li><strong>Feature Request</strong> for additions or enhancements</li><li><strong>General Support Request</strong> when the issue is broader than a bug</li></ul><p>Strong reports include exact package/version context, reproduction steps, and screenshots or minimal demos where possible.</p><h2 id="which-support-channels-are-available-today" tabindex="-1">Which support channels are available today? <a class="header-anchor" href="#which-support-channels-are-available-today" aria-label="Permalink to &quot;Which support channels are available today?&quot;">​</a></h2><p>Available today:</p><ul><li>GitHub Issues</li><li>GitHub Discussions</li></ul><p>Planned but not yet fully launched:</p><ul><li>live chat</li><li>office hours</li></ul><p>The docs should treat Issues and Discussions as the real support channels today.</p><h2 id="what-response-times-should-i-expect" tabindex="-1">What response times should I expect? <a class="header-anchor" href="#what-response-times-should-i-expect" aria-label="Permalink to &quot;What response times should I expect?&quot;">​</a></h2><p>The current docs guidance is:</p><ul><li>GitHub Issues: about 1–2 business days</li><li>GitHub Discussions: about 1–2 business days</li></ul><p>Do not assume same-day live chat support unless that channel is formally launched and documented.</p><h2 id="how-do-i-contribute-feedback-if-i-am-not-opening-code-right-away" tabindex="-1">How do I contribute feedback if I am not opening code right away? <a class="header-anchor" href="#how-do-i-contribute-feedback-if-i-am-not-opening-code-right-away" aria-label="Permalink to &quot;How do I contribute feedback if I am not opening code right away?&quot;">​</a></h2><p>Feedback does not need to start as a pull request.</p><p>Good entry points:</p><ul><li>GitHub Discussions for open-ended feedback</li><li>GitHub Issues for specific bugs, requests, or migration blockers</li><li>component or design proposal discussions when you are suggesting a larger change</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/cobalt-design-system/resources/contact.html">Contact</a></li><li><a href="/cobalt-design-system/contributing/how-to-contribute.html">How to Contribute</a></li><li><a href="/cobalt-design-system/guidance/migration.html">Migration Guides</a></li></ul>',35)])])}const b=a(i,[["render",r]]);export{c as __pageData,b as default};
